const evi_err_msg = 'Something went wrong! Please try after sometime.';

$(document).ready(function() {
    
    $(document).delegate('.reviewer-status-evi-upload', 'click', function(e) {

        e.preventDefault();

        let link = $(this);
        let res_container = link.closest('.evidence-uploader');
        let closestTr = link.closest('tr');

        $.ajax({
            url: link.attr('href'),
            type: 'GET',
            success: function(res) {

                try 
                {
                    res = JSON.parse(res);
            
                    // has error
                    if(res.err)
                        $( res_container ).html('<span class="d-block text-danger font-sm mt-2">'+ res.msg +'</span>');
                    else
                    {
                        // display markup
                        $( res_container ).html(res.markup);

                        if( res.status_id !== undefined && res.status_id == '2' )
                        {
                            let reviewerAction = closestTr.find('.reviewer-action .form-select');

                            if(reviewerAction.length > 0)
                            {
                                // change to reassesment
                                $(reviewerAction[0]).val(3);

                                if(res.annex !== undefined && res.annex == true)
                                {
                                    closestTr = closestTr.closest('table').parent().parent();

                                    // find closest tbody
                                    let annexQuestion = closestTr.prev('tr');

                                    if(annexQuestion.length > 0)
                                    {
                                        reviewerAction = $(annexQuestion[0]).find('.reviewer-action .form-select');
                                        $(reviewerAction[0]).val(3);
                                    }
                                }   
                            }
                        }
                    }

                } 
                catch (error) { alert(evi_err_msg); }
            },
            
            error: function() { alert(evi_err_msg); }
        });

        return false;

    });

});